import React, { useState, useContext } from 'react';
import { Truck, User, Phone, Mail, MapPin, IdCard, Car, Save, ArrowLeft, Eye, EyeOff, Calendar, FileText } from 'lucide-react';
import { useNavigation } from '../../../contexts/NavigationContext';

interface CourierFormData {
  personalInfo: {
    firstName: string;
    lastName: string;
    email: string;
    phone: string;
    address: string;
    dateOfBirth: string;
    idNumber: string;
    emergencyContact: {
      name: string;
      phone: string;
      relationship: string;
    };
  };
  vehicleInfo: {
    type: string;
    make: string;
    model: string;
    year: string;
    licensePlate: string;
    color: string;
    insurance: {
      company: string;
      policyNumber: string;
      expirationDate: string;
    };
  };
  employment: {
    employmentType: string;
    startDate: string;
    hourlyRate: string;
    bankAccount: {
      bankName: string;
      accountNumber: string;
      routingNumber: string;
    };
  };
  credentials: {
    licenseNumber: string;
    licenseExpiration: string;
    backgroundCheck: boolean;
    drugTest: boolean;
    trainingCompleted: boolean;
  };
  workPreferences: {
    availability: string[];
    preferredZones: string[];
    maxPackagesPerDay: string;
    specializations: string[];
  };
}

const NewCourierPage: React.FC = () => {
  const { navigate  } = useNavigation();
  const [currentStep, setCurrentStep] = useState(1);
  const [showBankInfo, setShowBankInfo] = useState(false);
  
  const [formData, setFormData] = useState<CourierFormData>({
    personalInfo: {
      firstName: '',
      lastName: '',
      email: '',
      phone: '',
      address: '',
      dateOfBirth: '',
      idNumber: '',
      emergencyContact: {
        name: '',
        phone: '',
        relationship: ''
      }
    },
    vehicleInfo: {
      type: '',
      make: '',
      model: '',
      year: '',
      licensePlate: '',
      color: '',
      insurance: {
        company: '',
        policyNumber: '',
        expirationDate: ''
      }
    },
    employment: {
      employmentType: '',
      startDate: '',
      hourlyRate: '',
      bankAccount: {
        bankName: '',
        accountNumber: '',
        routingNumber: ''
      }
    },
    credentials: {
      licenseNumber: '',
      licenseExpiration: '',
      backgroundCheck: false,
      drugTest: false,
      trainingCompleted: false
    },
    workPreferences: {
      availability: [],
      preferredZones: [],
      maxPackagesPerDay: '',
      specializations: []
    }
  });

  const handleInputChange = (section: string, field: string, value: any, subField?: string) => {
    setFormData(prev => ({
      ...prev,
      [section]: {
        ...prev[section as keyof CourierFormData],
        [field]: subField ? {
          ...(prev[section as keyof CourierFormData] as any)[field],
          [subField]: value
        } : value
      }
    }));
  };

  const handleArrayChange = (section: string, field: string, value: string, checked: boolean) => {
    setFormData(prev => {
      const currentArray = (prev[section as keyof CourierFormData] as any)[field] as string[];
      const newArray = checked 
        ? [...currentArray, value]
        : currentArray.filter(item => item !== value);
      
      return {
        ...prev,
        [section]: {
          ...prev[section as keyof CourierFormData],
          [field]: newArray
        }
      };
    });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    console.log('Crear courier:', formData);
    alert('Courier registrado exitosamente!');
    navigate('couriers');
  };

  const nextStep = () => {
    if (currentStep < 5) setCurrentStep(currentStep + 1);
  };

  const prevStep = () => {
    if (currentStep > 1) setCurrentStep(currentStep - 1);
  };

  const steps = [
    { number: 1, title: 'Información Personal', icon: User },
    { number: 2, title: 'Vehículo', icon: Car },
    { number: 3, title: 'Empleo', icon: FileText },
    { number: 4, title: 'Credenciales', icon: IdCard },
    { number: 5, title: 'Preferencias', icon: Truck }
  ];

  return (
    <div className="p-6 lg:p-8 -mt-20">
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <div className="flex items-center space-x-3">
          <button 
            onClick={() => navigate('couriers')}
            className="p-2 hover:bg-gray-100 rounded-lg transition-colors"
          >
            <ArrowLeft className="w-6 h-6 text-gray-600" />
          </button>
          <Truck className="w-8 h-8 text-gray-600" />
          <div>
            <h1 className="text-3xl font-bold text-gray-900">Registrar Nuevo Courier</h1>
            <p className="text-gray-600">Completa la información para registrar un nuevo courier</p>
          </div>
        </div>
      </div>

      {/* Progress Steps */}
      <div className="mb-8">
        <div className="flex items-center justify-center space-x-4 overflow-x-auto">
          {steps.map((step, index) => {
            const Icon = step.icon;
            return (
              <div key={step.number} className="flex items-center">
                <div className={`flex flex-col items-center ${index < steps.length - 1 ? 'min-w-0' : ''}`}>
                  <div className={`w-12 h-12 rounded-full flex items-center justify-center text-sm font-medium ${
                    currentStep >= step.number ? 'bg-blue-600 text-white' : 'bg-gray-200 text-gray-600'
                  }`}>
                    <Icon className="w-5 h-5" />
                  </div>
                  <div className="mt-2 text-center">
                    <p className={`text-sm font-medium ${currentStep >= step.number ? 'text-blue-600' : 'text-gray-500'}`}>
                      Paso {step.number}
                    </p>
                    <p className="text-xs text-gray-500 max-w-20">{step.title}</p>
                  </div>
                </div>
                {index < steps.length - 1 && (
                  <div className={`w-12 h-0.5 mx-2 ${currentStep > step.number ? 'bg-blue-600' : 'bg-gray-200'}`}></div>
                )}
              </div>
            );
          })}
        </div>
      </div>

      <form onSubmit={handleSubmit} className="space-y-8">
        {/* Step 1: Personal Information */}
        {currentStep === 1 && (
          <div className="bg-white rounded-2xl shadow-xl p-8 border border-gray-100">
            <div className="flex items-center space-x-3 mb-6">
              <User className="w-6 h-6 text-blue-600" />
              <h2 className="text-xl font-semibold text-gray-900">Información Personal</h2>
            </div>
            
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Nombre *
                </label>
                <input
                  type="text"
                  value={formData.personalInfo.firstName}
                  onChange={(e) => handleInputChange('personalInfo', 'firstName', e.target.value)}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  placeholder="Nombre del courier"
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Apellido *
                </label>
                <input
                  type="text"
                  value={formData.personalInfo.lastName}
                  onChange={(e) => handleInputChange('personalInfo', 'lastName', e.target.value)}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  placeholder="Apellido del courier"
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Email *
                </label>
                <input
                  type="email"
                  value={formData.personalInfo.email}
                  onChange={(e) => handleInputChange('personalInfo', 'email', e.target.value)}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  placeholder="email@ejemplo.com"
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Teléfono *
                </label>
                <input
                  type="tel"
                  value={formData.personalInfo.phone}
                  onChange={(e) => handleInputChange('personalInfo', 'phone', e.target.value)}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  placeholder="+1 (555) 123-4567"
                  required
                />
              </div>

              <div className="md:col-span-2">
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Dirección *
                </label>
                <textarea
                  rows={3}
                  value={formData.personalInfo.address}
                  onChange={(e) => handleInputChange('personalInfo', 'address', e.target.value)}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  placeholder="Dirección completa"
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Fecha de Nacimiento *
                </label>
                <input
                  type="date"
                  value={formData.personalInfo.dateOfBirth}
                  onChange={(e) => handleInputChange('personalInfo', 'dateOfBirth', e.target.value)}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Número de Identificación *
                </label>
                <input
                  type="text"
                  value={formData.personalInfo.idNumber}
                  onChange={(e) => handleInputChange('personalInfo', 'idNumber', e.target.value)}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  placeholder="Número de ID o Pasaporte"
                  required
                />
              </div>

              {/* Emergency Contact */}
              <div className="md:col-span-2">
                <h3 className="text-lg font-medium text-gray-900 mb-4">Contacto de Emergencia</h3>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                      Nombre Completo
                    </label>
                    <input
                      type="text"
                      value={formData.personalInfo.emergencyContact.name}
                      onChange={(e) => handleInputChange('personalInfo', 'emergencyContact', e.target.value, 'name')}
                      className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                      placeholder="Nombre del contacto"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                      Teléfono
                    </label>
                    <input
                      type="tel"
                      value={formData.personalInfo.emergencyContact.phone}
                      onChange={(e) => handleInputChange('personalInfo', 'emergencyContact', e.target.value, 'phone')}
                      className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                      placeholder="+1 (555) 987-6543"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                      Parentesco
                    </label>
                    <select
                      value={formData.personalInfo.emergencyContact.relationship}
                      onChange={(e) => handleInputChange('personalInfo', 'emergencyContact', e.target.value, 'relationship')}
                      className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                    >
                      <option value="">Seleccionar</option>
                      <option value="spouse">Cónyuge</option>
                      <option value="parent">Padre/Madre</option>
                      <option value="sibling">Hermano/a</option>
                      <option value="child">Hijo/a</option>
                      <option value="friend">Amigo/a</option>
                      <option value="other">Otro</option>
                    </select>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Step 2: Vehicle Information */}
        {currentStep === 2 && (
          <div className="bg-white rounded-2xl shadow-xl p-8 border border-gray-100">
            <div className="flex items-center space-x-3 mb-6">
              <Car className="w-6 h-6 text-green-600" />
              <h2 className="text-xl font-semibold text-gray-900">Información del Vehículo</h2>
            </div>
            
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Tipo de Vehículo *
                </label>
                <select
                  value={formData.vehicleInfo.type}
                  onChange={(e) => handleInputChange('vehicleInfo', 'type', e.target.value)}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
                  required
                >
                  <option value="">Seleccionar tipo</option>
                  <option value="car">Automóvil</option>
                  <option value="van">Van</option>
                  <option value="truck">Camión</option>
                  <option value="motorcycle">Motocicleta</option>
                  <option value="bicycle">Bicicleta</option>
                </select>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Marca *
                </label>
                <input
                  type="text"
                  value={formData.vehicleInfo.make}
                  onChange={(e) => handleInputChange('vehicleInfo', 'make', e.target.value)}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
                  placeholder="ej: Toyota, Ford, Honda"
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Modelo *
                </label>
                <input
                  type="text"
                  value={formData.vehicleInfo.model}
                  onChange={(e) => handleInputChange('vehicleInfo', 'model', e.target.value)}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
                  placeholder="ej: Corolla, F-150, Civic"
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Año *
                </label>
                <input
                  type="number"
                  min="1990"
                  max="2025"
                  value={formData.vehicleInfo.year}
                  onChange={(e) => handleInputChange('vehicleInfo', 'year', e.target.value)}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
                  placeholder="2020"
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Placa *
                </label>
                <input
                  type="text"
                  value={formData.vehicleInfo.licensePlate}
                  onChange={(e) => handleInputChange('vehicleInfo', 'licensePlate', e.target.value.toUpperCase())}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
                  placeholder="ABC-1234"
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Color
                </label>
                <input
                  type="text"
                  value={formData.vehicleInfo.color}
                  onChange={(e) => handleInputChange('vehicleInfo', 'color', e.target.value)}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
                  placeholder="ej: Blanco, Negro, Azul"
                />
              </div>

              {/* Insurance Information */}
              <div className="md:col-span-2">
                <h3 className="text-lg font-medium text-gray-900 mb-4">Información del Seguro</h3>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                      Compañía de Seguro *
                    </label>
                    <input
                      type="text"
                      value={formData.vehicleInfo.insurance.company}
                      onChange={(e) => handleInputChange('vehicleInfo', 'insurance', e.target.value, 'company')}
                      className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
                      placeholder="Nombre de la aseguradora"
                      required
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                      Número de Póliza *
                    </label>
                    <input
                      type="text"
                      value={formData.vehicleInfo.insurance.policyNumber}
                      onChange={(e) => handleInputChange('vehicleInfo', 'insurance', e.target.value, 'policyNumber')}
                      className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
                      placeholder="Número de póliza"
                      required
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                      Fecha de Vencimiento *
                    </label>
                    <input
                      type="date"
                      value={formData.vehicleInfo.insurance.expirationDate}
                      onChange={(e) => handleInputChange('vehicleInfo', 'insurance', e.target.value, 'expirationDate')}
                      className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
                      required
                    />
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Step 3: Employment Information */}
        {currentStep === 3 && (
          <div className="bg-white rounded-2xl shadow-xl p-8 border border-gray-100">
            <div className="flex items-center space-x-3 mb-6">
              <FileText className="w-6 h-6 text-purple-600" />
              <h2 className="text-xl font-semibold text-gray-900">Información de Empleo</h2>
            </div>
            
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Tipo de Empleo *
                </label>
                <select
                  value={formData.employment.employmentType}
                  onChange={(e) => handleInputChange('employment', 'employmentType', e.target.value)}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-purple-500 focus:border-transparent"
                  required
                >
                  <option value="">Seleccionar</option>
                  <option value="full-time">Tiempo Completo</option>
                  <option value="part-time">Tiempo Parcial</option>
                  <option value="contractor">Contratista</option>
                  <option value="freelance">Freelance</option>
                </select>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Fecha de Inicio *
                </label>
                <input
                  type="date"
                  value={formData.employment.startDate}
                  onChange={(e) => handleInputChange('employment', 'startDate', e.target.value)}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-purple-500 focus:border-transparent"
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Tarifa por Hora ($) *
                </label>
                <input
                  type="number"
                  step="0.01"
                  min="0"
                  value={formData.employment.hourlyRate}
                  onChange={(e) => handleInputChange('employment', 'hourlyRate', e.target.value)}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-purple-500 focus:border-transparent"
                  placeholder="15.00"
                  required
                />
              </div>

              {/* Bank Account Information */}
              <div className="md:col-span-2">
                <div className="flex items-center justify-between mb-4">
                  <h3 className="text-lg font-medium text-gray-900">Información Bancaria</h3>
                  <button
                    type="button"
                    onClick={() => setShowBankInfo(!showBankInfo)}
                    className="flex items-center space-x-2 text-purple-600 hover:text-purple-700"
                  >
                    {showBankInfo ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                    <span>{showBankInfo ? 'Ocultar' : 'Mostrar'} información</span>
                  </button>
                </div>
                
                {showBankInfo && (
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">
                        Banco *
                      </label>
                      <input
                        type="text"
                        value={formData.employment.bankAccount.bankName}
                        onChange={(e) => handleInputChange('employment', 'bankAccount', e.target.value, 'bankName')}
                        className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-purple-500 focus:border-transparent"
                        placeholder="Nombre del banco"
                        required
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">
                        Número de Cuenta *
                      </label>
                      <input
                        type="text"
                        value={formData.employment.bankAccount.accountNumber}
                        onChange={(e) => handleInputChange('employment', 'bankAccount', e.target.value, 'accountNumber')}
                        className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-purple-500 focus:border-transparent"
                        placeholder="Número de cuenta"
                        required
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">
                        Número de Routing *
                      </label>
                      <input
                        type="text"
                        value={formData.employment.bankAccount.routingNumber}
                        onChange={(e) => handleInputChange('employment', 'bankAccount', e.target.value, 'routingNumber')}
                        className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-purple-500 focus:border-transparent"
                        placeholder="Routing number"
                        required
                      />
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}

        {/* Step 4: Credentials */}
        {currentStep === 4 && (
          <div className="bg-white rounded-2xl shadow-xl p-8 border border-gray-100">
            <div className="flex items-center space-x-3 mb-6">
              <IdCard className="w-6 h-6 text-orange-600" />
              <h2 className="text-xl font-semibold text-gray-900">Credenciales y Verificaciones</h2>
            </div>
            
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Número de Licencia de Conducir *
                </label>
                <input
                  type="text"
                  value={formData.credentials.licenseNumber}
                  onChange={(e) => handleInputChange('credentials', 'licenseNumber', e.target.value)}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 focus:border-transparent"
                  placeholder="Número de licencia"
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Fecha de Vencimiento de Licencia *
                </label>
                <input
                  type="date"
                  value={formData.credentials.licenseExpiration}
                  onChange={(e) => handleInputChange('credentials', 'licenseExpiration', e.target.value)}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 focus:border-transparent"
                  required
                />
              </div>

              {/* Verification Checkboxes */}
              <div className="md:col-span-2">
                <h3 className="text-lg font-medium text-gray-900 mb-4">Verificaciones Requeridas</h3>
                <div className="space-y-4">
                  <label className="flex items-center space-x-3">
                    <input
                      type="checkbox"
                      checked={formData.credentials.backgroundCheck}
                      onChange={(e) => handleInputChange('credentials', 'backgroundCheck', e.target.checked)}
                      className="w-5 h-5 text-orange-600 border-gray-300 rounded focus:ring-orange-500"
                    />
                    <div>
                      <span className="text-sm font-medium text-gray-900">Verificación de Antecedentes</span>
                      <p className="text-xs text-gray-600">Confirmación de historial criminal limpio</p>
                    </div>
                  </label>

                  <label className="flex items-center space-x-3">
                    <input
                      type="checkbox"
                      checked={formData.credentials.drugTest}
                      onChange={(e) => handleInputChange('credentials', 'drugTest', e.target.checked)}
                      className="w-5 h-5 text-orange-600 border-gray-300 rounded focus:ring-orange-500"
                    />
                    <div>
                      <span className="text-sm font-medium text-gray-900">Prueba de Drogas</span>
                      <p className="text-xs text-gray-600">Resultado negativo en prueba de sustancias</p>
                    </div>
                  </label>

                  <label className="flex items-center space-x-3">
                    <input
                      type="checkbox"
                      checked={formData.credentials.trainingCompleted}
                      onChange={(e) => handleInputChange('credentials', 'trainingCompleted', e.target.checked)}
                      className="w-5 h-5 text-orange-600 border-gray-300 rounded focus:ring-orange-500"
                    />
                    <div>
                      <span className="text-sm font-medium text-gray-900">Entrenamiento Completado</span>
                      <p className="text-xs text-gray-600">Capacitación en procesos y seguridad</p>
                    </div>
                  </label>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Step 5: Work Preferences */}
        {currentStep === 5 && (
          <div className="bg-white rounded-2xl shadow-xl p-8 border border-gray-100">
            <div className="flex items-center space-x-3 mb-6">
              <Truck className="w-6 h-6 text-red-600" />
              <h2 className="text-xl font-semibold text-gray-900">Preferencias de Trabajo</h2>
            </div>
            
            <div className="space-y-6">
              {/* Availability */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-3">
                  Disponibilidad (selecciona todos los días que apliquen)
                </label>
                <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                  {['Lunes', 'Martes', 'Miércoles', 'Jueves', 'Viernes', 'Sábado', 'Domingo'].map((day) => (
                    <label key={day} className="flex items-center space-x-2">
                      <input
                        type="checkbox"
                        checked={formData.workPreferences.availability.includes(day)}
                        onChange={(e) => handleArrayChange('workPreferences', 'availability', day, e.target.checked)}
                        className="w-4 h-4 text-red-600 border-gray-300 rounded focus:ring-red-500"
                      />
                      <span className="text-sm text-gray-900">{day}</span>
                    </label>
                  ))}
                </div>
              </div>

              {/* Preferred Zones */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-3">
                  Zonas Preferidas
                </label>
                <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                  {['Miami-Dade', 'Broward', 'Palm Beach', 'Orlando', 'Tampa', 'Jacksonville', 'Key West', 'Fort Lauderdale', 'Pensacola'].map((zone) => (
                    <label key={zone} className="flex items-center space-x-2">
                      <input
                        type="checkbox"
                        checked={formData.workPreferences.preferredZones.includes(zone)}
                        onChange={(e) => handleArrayChange('workPreferences', 'preferredZones', zone, e.target.checked)}
                        className="w-4 h-4 text-red-600 border-gray-300 rounded focus:ring-red-500"
                      />
                      <span className="text-sm text-gray-900">{zone}</span>
                    </label>
                  ))}
                </div>
              </div>

              {/* Max Packages */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Máximo de Paquetes por Día
                </label>
                <select
                  value={formData.workPreferences.maxPackagesPerDay}
                  onChange={(e) => handleInputChange('workPreferences', 'maxPackagesPerDay', e.target.value)}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-red-500 focus:border-transparent"
                >
                  <option value="">Seleccionar</option>
                  <option value="10">Hasta 10 paquetes</option>
                  <option value="20">Hasta 20 paquetes</option>
                  <option value="30">Hasta 30 paquetes</option>
                  <option value="50">Hasta 50 paquetes</option>
                  <option value="unlimited">Sin límite</option>
                </select>
              </div>

              {/* Specializations */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-3">
                  Especializaciones
                </label>
                <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                  {['Paquetes Frágiles', 'Documentos', 'Electrónicos', 'Medicamentos', 'Alimentos', 'Productos Químicos', 'Entregas Express', 'Entregas Nocturnas'].map((spec) => (
                    <label key={spec} className="flex items-center space-x-2">
                      <input
                        type="checkbox"
                        checked={formData.workPreferences.specializations.includes(spec)}
                        onChange={(e) => handleArrayChange('workPreferences', 'specializations', spec, e.target.checked)}
                        className="w-4 h-4 text-red-600 border-gray-300 rounded focus:ring-red-500"
                      />
                      <span className="text-sm text-gray-900">{spec}</span>
                    </label>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Navigation Buttons */}
        <div className="flex items-center justify-between pt-6">
          <div>
            {currentStep > 1 && (
              <button
                type="button"
                onClick={prevStep}
                className="flex items-center space-x-2 px-6 py-3 border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors"
              >
                <ArrowLeft className="w-4 h-4" />
                <span>Anterior</span>
              </button>
            )}
          </div>

          <div className="flex items-center space-x-4">
            {currentStep < 5 ? (
              <button
                type="button"
                onClick={nextStep}
                className="flex items-center space-x-2 px-6 py-3 bg-gradient-to-r from-blue-600 to-purple-600 text-white rounded-lg hover:from-blue-700 hover:to-purple-700 transition-all duration-200"
              >
                <span>Siguiente</span>
              </button>
            ) : (
              <button
                type="submit"
                className="flex items-center space-x-2 px-8 py-3 bg-gradient-to-r from-green-600 to-blue-600 text-white rounded-lg hover:from-green-700 hover:to-blue-700 transition-all duration-200 shadow-lg hover:shadow-xl"
              >
                <Save className="w-5 h-5" />
                <span>Registrar Courier</span>
              </button>
            )}
          </div>
        </div>
      </form>
    </div>
  );
};

export default NewCourierPage;